<?php
 namespace League\CommonMark\Extension\Mention; use League\CommonMark\Extension\Mention\Generator\CallbackGenerator; use League\CommonMark\Extension\Mention\Generator\MentionGeneratorInterface; use League\CommonMark\Extension\Mention\Generator\StringTemplateLinkGenerator; use League\CommonMark\Inline\Parser\InlineParserInterface; use League\CommonMark\InlineParserContext; final class MentionParser implements InlineParserInterface { private $symbol; private $mentionRegex; private $mentionGenerator; public function __construct(string $symbol, string $mentionRegex, MentionGeneratorInterface $mentionGenerator) { $this->symbol = $symbol; $this->mentionRegex = $mentionRegex; $this->mentionGenerator = $mentionGenerator; } public function getCharacters(): array { return [$this->symbol]; } public function parse(InlineParserContext $inlineContext): bool { $cursor = $inlineContext->getCursor(); $previousChar = $cursor->peek(-1); if ($previousChar !== null && \preg_match('/\w/', $previousChar)) { return false; } $previousState = $cursor->saveState(); $cursor->advance(); $identifier = $cursor->match($this->mentionRegex); if ($identifier === null) { $cursor->restoreState($previousState); return false; } $mention = $this->mentionGenerator->generateMention(new Mention($this->symbol, $identifier)); if ($mention === null) { $cursor->restoreState($previousState); return false; } $inlineContext->getContainer()->appendChild($mention); return true; } public static function createWithStringTemplate(string $symbol, string $mentionRegex, string $urlTemplate): MentionParser { return new self($symbol, $mentionRegex, new StringTemplateLinkGenerator($urlTemplate)); } public static function createWithCallback(string $symbol, string $mentionRegex, callable $callback): MentionParser { return new self($symbol, $mentionRegex, new CallbackGenerator($callback)); } } 